#include "LapesEye/core/SonyILCE7M3Profile.h"
#include <QImage>
#include <cmath>

namespace LapesEye {

// ─── Aplikacja HueSatMap na QImage ───────────────────────────────────────────
// Stosuje profil Adobe Standard: korekcja odcienia i nasycenia per-piksel
// przez interpolację w tablicy HSM 90×30

static void rgb_to_hsv(float r, float g, float b,
                        float& h, float& s, float& v) {
    float mx = std::max({r, g, b});
    float mn = std::min({r, g, b});
    float d  = mx - mn;
    v = mx;
    s = mx > 0.f ? d / mx : 0.f;
    if (d < 1e-6f) { h = 0.f; return; }
    if      (mx == r) h = 60.f * std::fmod((g - b) / d, 6.f);
    else if (mx == g) h = 60.f * ((b - r) / d + 2.f);
    else              h = 60.f * ((r - g) / d + 4.f);
    if (h < 0.f) h += 360.f;
}

static void hsv_to_rgb(float h, float s, float v,
                        float& r, float& g, float& b) {
    float c = v * s;
    float x = c * (1.f - std::fabs(std::fmod(h / 60.f, 2.f) - 1.f));
    float m = v - c;
    int   i = (int)(h / 60.f) % 6;
    float r1, g1, b1;
    switch (i) {
        case 0: r1=c; g1=x; b1=0; break;
        case 1: r1=x; g1=c; b1=0; break;
        case 2: r1=0; g1=c; b1=x; break;
        case 3: r1=0; g1=x; b1=c; break;
        case 4: r1=x; g1=0; b1=c; break;
        default:r1=c; g1=0; b1=x; break;
    }
    r = r1 + m; g = g1 + m; b = b1 + m;
}

QImage apply_sony_ilce7m3_profile(const QImage& src) {
    QImage result = src.convertToFormat(QImage::Format_RGB32);
    const int w = result.width(), h = result.height();

    const int hue_divs = SONY_ILCE7M3_HSM_HUE_DIVS;  // 90
    const int sat_divs = SONY_ILCE7M3_HSM_SAT_DIVS;  // 30

    for (int y = 0; y < h; ++y) {
        QRgb* line = reinterpret_cast<QRgb*>(result.scanLine(y));
        for (int x = 0; x < w; ++x) {
            QRgb px = line[x];
            float r = qRed(px)   / 255.f;
            float g = qGreen(px) / 255.f;
            float b = qBlue(px)  / 255.f;

            float hh, ss, vv;
            rgb_to_hsv(r, g, b, hh, ss, vv);

            // Indeks w tablicy HSM (bilinearna interpolacja)
            float hue_idx = (hh / 360.f) * hue_divs;
            float sat_idx = ss * (sat_divs - 1);

            int hi0 = (int)hue_idx % hue_divs;
            int hi1 = (hi0 + 1) % hue_divs;
            int si0 = std::min((int)sat_idx, sat_divs - 1);
            int si1 = std::min(si0 + 1, sat_divs - 1);
            float hf = hue_idx - (int)hue_idx;
            float sf = sat_idx - (int)sat_idx;

            // 4 punkty interpolacji
            auto hsm_val = [&](int hi, int si, int ch) -> float {
                return SONY_ILCE7M3_HSM_D65[(hi * sat_divs + si) * 3 + ch];
            };

            float h_shift = (1-hf)*(1-sf)*hsm_val(hi0,si0,0)
                          + hf    *(1-sf)*hsm_val(hi1,si0,0)
                          + (1-hf)*sf    *hsm_val(hi0,si1,0)
                          + hf    *sf    *hsm_val(hi1,si1,0);
            float s_scale = (1-hf)*(1-sf)*hsm_val(hi0,si0,1)
                          + hf    *(1-sf)*hsm_val(hi1,si0,1)
                          + (1-hf)*sf    *hsm_val(hi0,si1,1)
                          + hf    *sf    *hsm_val(hi1,si1,1);
            float v_scale = (1-hf)*(1-sf)*hsm_val(hi0,si0,2)
                          + hf    *(1-sf)*hsm_val(hi1,si0,2)
                          + (1-hf)*sf    *hsm_val(hi0,si1,2)
                          + hf    *sf    *hsm_val(hi1,si1,2);

            hh = std::fmod(hh + h_shift, 360.f);
            if (hh < 0.f) hh += 360.f;
            ss = std::min(1.f, ss * s_scale);
            vv = std::min(1.f, vv * v_scale);

            hsv_to_rgb(hh, ss, vv, r, g, b);
            int ri = std::clamp((int)(r * 255.f + .5f), 0, 255);
            int gi = std::clamp((int)(g * 255.f + .5f), 0, 255);
            int bi = std::clamp((int)(b * 255.f + .5f), 0, 255);
            line[x] = qRgb(ri, gi, bi);
        }
    }
    return result;
}

} // namespace LapesEye
